//TASK IMPLEMANTATIONS

void vSensorTask(void *pvParameters) {
    DHT11_Data_t sensorData;

    while(1) {
        // Communication Process starts
        BSP_DTH11_start(); // send 18ms wake up pulse

        // check up for handshake response Low or High
        if (BSP_DTH11_Response()) {
            // Read all 40 bits of data and verify check sum
            sensorData = BSP_DTH11_ReadData();
        } else {
            // Mark data as invalid if the sensor times out
            sensorData.valid = 0;
        }

        // Send the packaged struct to both consumer tasks
        // We use a block time of 0 so the sensor task never gets stuck
        xQueueSend(xDisplayQueue, &sensorData, 0);
        xQueueSend(xCommQueue, &sensorData, 0);

        // RTOS Delay instead of bare-metal delay
        vTaskDelay(pdMS_TO_TICKS(2000));
    }
}

void vDisplayTask(void *pvParameters) {
    DHT11_Data_t receivedData;

    while(1) {
        // Block indefinitely until new sensor data arrives in the queue
        if (xQueueReceive(xDisplayQueue, &receivedData, portMAX_DELAY) == pdPASS) {
            // Handling data to Display module
            Display_Update(receivedData);
        }
    }
}

void vCommTask(void *pvParameters) {
    DHT11_Data_t receivedData;

    while(1) {
        // Block indefinitely until new sensor data arrives in the queue
        if (xQueueReceive(xCommQueue, &receivedData, portMAX_DELAY) == pdPASS) {

            // Safely acquire the UART Mutex before transmitting
            if (xSemaphoreTake(xUartMutex, portMAX_DELAY) == pdTRUE) {

                // Handling UART Transmission using exact project strings
                if(receivedData.valid) {
                    BSP_USART2_SendString("Sensor Data Read Successfully\r\n");
                } else {
                    BSP_USART2_SendString("Sensor Timeout or Checksum Error\r\n");
                }

                // Release the UART Mutex
                xSemaphoreGive(xUartMutex);
            }
        }
    }
}
